import React, { Component } from "react";
import Typical from "react-typical";
import Switch from "react-switch";
import { motion } from "framer-motion";

class Header extends Component {
  constructor() {
    super();
    this.state = { checked: false };
    this.onThemeSwitchChange = this.onThemeSwitchChange.bind(this);
  }

  componentDidMount() {
    const currentTheme = document.body.getAttribute("data-theme");
    this.setState({ checked: currentTheme === "dark" });
  }

  onThemeSwitchChange(checked) {
    this.setState({ checked });
    this.setTheme(checked);
  }

  setTheme(checked) {
    const dataThemeAttribute = "data-theme";
    const body = document.body;
    const newTheme = checked ? "dark" : "light";
    body.setAttribute(dataThemeAttribute, newTheme);
  }

  // New function to handle smooth scrolling to the center
  scrollToSection = (e, id) => {
    e.preventDefault();
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({
        behavior: "smooth",
        block: "center", // This centers the section on the screen
      });
    }
  };

  render() {
    let name = "";
    let titles = [];
    let sectionNames = {
      about: "About",
      projects: "Projects",
      skills: "Skills",
      experience: "Experience"
    };

    if (this.props.sharedData) {
      name = this.props.sharedData.name;
      titles = this.props.sharedData.titles.map(x => [x.toUpperCase(), 1500]).flat();
    }

    const HeaderTitleTypeAnimation = React.memo(() => {
      return <Typical className="title-styles" steps={titles} loop={50} />
    }, () => true);

    const containerVariants = {
      hidden: { opacity: 0, y: 30 },
      visible: { 
        opacity: 1, 
        y: 0,
        transition: { duration: 0.8, ease: "easeOut", staggerChildren: 0.2 }
      }
    };

    const childVariants = {
      hidden: { opacity: 0, y: 20 },
      visible: { opacity: 1, y: 0 }
    };

    return (
      <header id="home" style={{ 
        height: '100vh', 
        minHeight: '500px',
        display: 'block',
        background: 'var(--body-background)',
        transition: 'background-color 0.6s ease',
        position: 'relative'
      }}>

        {/* TOP NAVIGATION BAR */}
        <nav style={{
          position: "absolute",
          top: "30px",
          right: "50px",
          zIndex: 1000,
          display: "flex",
          gap: "30px"
        }}>
          {['about', 'projects', 'skills', 'experience'].map((item) => (
            <motion.button
              key={item}
              onClick={(e) => this.scrollToSection(e, item)}
              style={{
                background: "none",
                border: "none",
                cursor: "pointer",
                color: "var(--header-text)",
                fontSize: "1.1rem",
                fontWeight: "600",
                textTransform: "uppercase",
                letterSpacing: "1px",
                transition: "color 0.3s ease",
                padding: "5px 10px"
              }}
              whileHover={{ 
                scale: 1.1, 
                color: "#AE944F" 
              }}
              whileTap={{ scale: 0.95 }}
            >
              {sectionNames[item]}
            </motion.button>
          ))}
        </nav>

        <div className="row aligner" style={{ height: '100%', margin: 0 }}>
          <motion.div 
            className="col-md-12"
            initial="hidden"
            animate="visible"
            variants={containerVariants}
          >
            <div>
              <motion.div
                animate={{ y: [0, -15, 0] }}
                transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
              >
                <span 
                  className="iconify header-icon" 
                  data-icon="la:laptop-code" 
                  data-inline="false"
                  style={{ color: 'var(--header-text)' }}
                ></span>
              </motion.div>

              <br />

              <motion.h1 
                className="mb-0" 
                variants={childVariants}
                style={{ color: 'var(--header-text)', fontWeight: '700' }}
              >
                <Typical steps={[name]} wrapper="p" />
              </motion.h1>

              <motion.div className="title-container" variants={childVariants}>
                <HeaderTitleTypeAnimation />
              </motion.div>

              <motion.div 
                variants={childVariants} 
                style={{ 
                  marginTop: '40px', 
                  width: 'fit-content', 
                  margin: '40px auto 0 auto', 
                  borderRadius: '30px',
                  padding: '6px', 
                  display: 'flex',
                  justifyContent: 'center',
                  background: 'rgba(174,148,79, 0.1)',
                }} 
                whileHover={{ 
                  scale: 1.05,
                  boxShadow: "0px 0px 20px rgba(174,148,79, 0.3)" 
                }} 
                whileTap={{ scale: 0.95 }}
              >
                <Switch
                  checked={this.state.checked}
                  onChange={this.onThemeSwitchChange}
                  offColor="#baaa80"
                  onColor="#353535"
                  className="react-switch mx-auto"
                  width={90}
                  height={40}
                  uncheckedIcon={
                    <span 
                      className="iconify" 
                      data-icon="twemoji:owl" 
                      style={{ 
                        display: "flex", 
                        alignItems: "center", 
                        justifyContent: "center", 
                        height: "100%", 
                        fontSize: 25,
                        marginLeft: "15px"
                      }}
                    ></span>
                  }
                  checkedIcon={
                    <span 
                      className="iconify" 
                      data-icon="noto-v1:sun-with-face" 
                      style={{ 
                        display: "flex", 
                        alignItems: "center", 
                        justifyContent: "center", 
                        height: "100%", 
                        fontSize: 25,
                        marginLeft: "10px"
                      }}
                    ></span>
                  }
                  id="icon-switch"
                />
              </motion.div>
            </div>
          </motion.div>
        </div>
      </header>
    );
  }
}

export default Header;
